"""
نظام مراقبة التخزين المؤقت المتقدم
"""

import time
import logging
from typing import Dict, List, Any, Optional
from datetime import datetime, timedelta
from django.utils import timezone
from django.core.cache import cache
from django.conf import settings
from dataclasses import dataclass, asdict
from collections import defaultdict, deque
import threading
import json

logger = logging.getLogger('hr_cache_monitor')


@dataclass
class CacheMetric:
    """مقياس التخزين المؤقت"""
    timestamp: datetime
    key: str
    operation: str  # get, set, delete, hit, miss
    size: int = 0
    duration: float = 0.0
    level: str = 'L1'
    tags: List[str] = None
    
    def __post_init__(self):
        if self.tags is None:
            self.tags = []


class CacheMonitor:
    """مراقب التخزين المؤقت المتقدم"""
    
    def __init__(self, max_metrics: int = 10000):
        self.max_metrics = max_metrics
        self.metrics = deque(maxlen=max_metrics)
        self.aggregated_stats = defaultdict(lambda: defaultdict(int))
        self.performance_thresholds = {
            'slow_query_ms': 100,
            'high_miss_rate': 50,  # نسبة مئوية
            'large_object_kb': 100,
        }
        self.alerts = []
        self.lock = threading.Lock()
        
        # بدء مراقبة دورية
        self._start_monitoring()
    
    def record_metric(self, metric: CacheMetric):
        """تسجيل مقياس جديد"""
        
        with self.lock:
            self.metrics.append(metric)
            
            # تحديث الإحصائيات المجمعة
            self._update_aggregated_stats(metric)
            
            # فحص التنبيهات
            self._check_alerts(metric)
    
    def _update_aggregated_stats(self, metric: CacheMetric):
        """تحديث الإحصائيات المجمعة"""
        
        # إحصائيات عامة
        self.aggregated_stats['total'][metric.operation] += 1
        self.aggregated_stats['total']['size'] += metric.size
        self.aggregated_stats['total']['duration'] += metric.duration
        
        # إحصائيات حسب المستوى
        self.aggregated_stats[metric.level][metric.operation] += 1
        
        # إحصائيات حسب العلامات
        for tag in metric.tags:
            self.aggregated_stats[f'tag:{tag}'][metric.operation] += 1
        
        # إحصائيات حسب الوقت (كل ساعة)\n        hour_key = metric.timestamp.strftime('%Y-%m-%d-%H')\n        self.aggregated_stats[f'hour:{hour_key}'][metric.operation] += 1\n    \n    def _check_alerts(self, metric: CacheMetric):\n        \"\"\"فحص التنبيهات\"\"\"\n        \n        alerts = []\n        \n        # تنبيه الاستعلام البطيء\n        if metric.duration > self.performance_thresholds['slow_query_ms']:\n            alerts.append({\n                'type': 'slow_query',\n                'message': f'استعلام بطيء: {metric.key} ({metric.duration:.2f}ms)',\n                'severity': 'warning',\n                'timestamp': metric.timestamp,\n                'details': asdict(metric)\n            })\n        \n        # تنبيه الكائن الكبير\n        if metric.size > self.performance_thresholds['large_object_kb'] * 1024:\n            alerts.append({\n                'type': 'large_object',\n                'message': f'كائن كبير: {metric.key} ({metric.size / 1024:.1f}KB)',\n                'severity': 'info',\n                'timestamp': metric.timestamp,\n                'details': asdict(metric)\n            })\n        \n        # إضافة التنبيهات\n        for alert in alerts:\n            self.alerts.append(alert)\n            logger.warning(f\"تنبيه التخزين المؤقت: {alert['message']}\")\n        \n        # الحفاظ على آخر 1000 تنبيه فقط\n        if len(self.alerts) > 1000:\n            self.alerts = self.alerts[-1000:]\n    \n    def get_stats(self, time_range: Optional[timedelta] = None) -> Dict[str, Any]:\n        \"\"\"الحصول على إحصائيات مفصلة\"\"\"\n        \n        with self.lock:\n            if time_range:\n                cutoff_time = timezone.now() - time_range\n                filtered_metrics = [m for m in self.metrics if m.timestamp >= cutoff_time]\n            else:\n                filtered_metrics = list(self.metrics)\n        \n        if not filtered_metrics:\n            return {'error': 'لا توجد مقاييس في النطاق الزمني المحدد'}\n        \n        # حساب الإحصائيات\n        total_operations = len(filtered_metrics)\n        hits = sum(1 for m in filtered_metrics if m.operation == 'hit')\n        misses = sum(1 for m in filtered_metrics if m.operation == 'miss')\n        sets = sum(1 for m in filtered_metrics if m.operation == 'set')\n        deletes = sum(1 for m in filtered_metrics if m.operation == 'delete')\n        \n        hit_rate = (hits / (hits + misses) * 100) if (hits + misses) > 0 else 0\n        \n        total_size = sum(m.size for m in filtered_metrics)\n        avg_size = total_size / total_operations if total_operations > 0 else 0\n        \n        total_duration = sum(m.duration for m in filtered_metrics)\n        avg_duration = total_duration / total_operations if total_operations > 0 else 0\n        \n        # أبطأ العمليات\n        slowest_operations = sorted(\n            filtered_metrics, \n            key=lambda m: m.duration, \n            reverse=True\n        )[:10]\n        \n        # أكبر الكائنات\n        largest_objects = sorted(\n            filtered_metrics,\n            key=lambda m: m.size,\n            reverse=True\n        )[:10]\n        \n        # الإحصائيات حسب المستوى\n        level_stats = defaultdict(lambda: {'hits': 0, 'misses': 0, 'sets': 0, 'deletes': 0})\n        for metric in filtered_metrics:\n            level_stats[metric.level][metric.operation] += 1\n        \n        # الإحصائيات حسب العلامات\n        tag_stats = defaultdict(lambda: {'hits': 0, 'misses': 0, 'sets': 0, 'deletes': 0})\n        for metric in filtered_metrics:\n            for tag in metric.tags:\n                tag_stats[tag][metric.operation] += 1\n        \n        return {\n            'summary': {\n                'total_operations': total_operations,\n                'hits': hits,\n                'misses': misses,\n                'sets': sets,\n                'deletes': deletes,\n                'hit_rate': round(hit_rate, 2),\n                'total_size_bytes': total_size,\n                'avg_size_bytes': round(avg_size, 2),\n                'total_duration_ms': round(total_duration, 2),\n                'avg_duration_ms': round(avg_duration, 2),\n            },\n            'performance': {\n                'slowest_operations': [\n                    {\n                        'key': m.key,\n                        'duration_ms': round(m.duration, 2),\n                        'operation': m.operation,\n                        'timestamp': m.timestamp.isoformat()\n                    } for m in slowest_operations\n                ],\n                'largest_objects': [\n                    {\n                        'key': m.key,\n                        'size_kb': round(m.size / 1024, 2),\n                        'operation': m.operation,\n                        'timestamp': m.timestamp.isoformat()\n                    } for m in largest_objects\n                ]\n            },\n            'level_stats': dict(level_stats),\n            'tag_stats': dict(tag_stats),\n            'alerts_count': len(self.alerts),\n            'time_range': str(time_range) if time_range else 'all_time'\n        }\n    \n    def get_alerts(self, severity: Optional[str] = None, limit: int = 100) -> List[Dict]:\n        \"\"\"الحصول على التنبيهات\"\"\"\n        \n        alerts = self.alerts\n        \n        if severity:\n            alerts = [a for a in alerts if a['severity'] == severity]\n        \n        return alerts[-limit:]\n    \n    def get_real_time_stats(self) -> Dict[str, Any]:\n        \"\"\"الحصول على إحصائيات الوقت الفعلي\"\"\"\n        \n        # آخر 5 دقائق\n        recent_stats = self.get_stats(timedelta(minutes=5))\n        \n        # معدل العمليات في الثانية\n        if recent_stats.get('summary', {}).get('total_operations', 0) > 0:\n            ops_per_second = recent_stats['summary']['total_operations'] / 300  # 5 دقائق\n        else:\n            ops_per_second = 0\n        \n        # حالة النظام\n        hit_rate = recent_stats.get('summary', {}).get('hit_rate', 0)\n        avg_duration = recent_stats.get('summary', {}).get('avg_duration_ms', 0)\n        \n        if hit_rate > 80 and avg_duration < 50:\n            system_health = 'excellent'\n        elif hit_rate > 60 and avg_duration < 100:\n            system_health = 'good'\n        elif hit_rate > 40 and avg_duration < 200:\n            system_health = 'fair'\n        else:\n            system_health = 'poor'\n        \n        return {\n            'current_time': timezone.now().isoformat(),\n            'operations_per_second': round(ops_per_second, 2),\n            'system_health': system_health,\n            'recent_stats': recent_stats['summary'],\n            'active_alerts': len([a for a in self.alerts if \n                                (timezone.now() - a['timestamp']).total_seconds() < 3600])\n        }\n    \n    def generate_report(self, time_range: timedelta = timedelta(days=1)) -> str:\n        \"\"\"إنتاج تقرير مفصل\"\"\"\n        \n        stats = self.get_stats(time_range)\n        alerts = self.get_alerts(limit=50)\n        \n        report_lines = [\n            \"=\" * 60,\n            \"تقرير أداء التخزين المؤقت\",\n            \"=\" * 60,\n            f\"النطاق الزمني: {time_range}\",\n            f\"تاريخ التقرير: {timezone.now().strftime('%Y-%m-%d %H:%M:%S')}\",\n            \"\",\n            \"الملخص العام:\",\n            \"-\" * 20,\n        ]\n        \n        if 'summary' in stats:\n            summary = stats['summary']\n            report_lines.extend([\n                f\"إجمالي العمليات: {summary['total_operations']:,}\",\n                f\"معدل الإصابة: {summary['hit_rate']:.2f}%\",\n                f\"متوسط وقت الاستجابة: {summary['avg_duration_ms']:.2f}ms\",\n                f\"إجمالي حجم البيانات: {summary['total_size_bytes'] / 1024 / 1024:.2f}MB\",\n                \"\"\n            ])\n        \n        # أداء العمليات\n        if 'performance' in stats:\n            report_lines.extend([\n                \"أبطأ العمليات:\",\n                \"-\" * 20\n            ])\n            \n            for op in stats['performance']['slowest_operations'][:5]:\n                report_lines.append(\n                    f\"  {op['key']}: {op['duration_ms']:.2f}ms ({op['operation']})\"\n                )\n            \n            report_lines.extend([\n                \"\",\n                \"أكبر الكائنات:\",\n                \"-\" * 20\n            ])\n            \n            for obj in stats['performance']['largest_objects'][:5]:\n                report_lines.append(\n                    f\"  {obj['key']}: {obj['size_kb']:.2f}KB ({obj['operation']})\"\n                )\n        \n        # التنبيهات الحديثة\n        if alerts:\n            report_lines.extend([\n                \"\",\n                \"التنبيهات الحديثة:\",\n                \"-\" * 20\n            ])\n            \n            for alert in alerts[-10:]:\n                report_lines.append(\n                    f\"  [{alert['severity'].upper()}] {alert['message']}\"\n                )\n        \n        # التوصيات\n        report_lines.extend([\n            \"\",\n            \"التوصيات:\",\n            \"-\" * 20\n        ])\n        \n        if 'summary' in stats:\n            hit_rate = stats['summary']['hit_rate']\n            avg_duration = stats['summary']['avg_duration_ms']\n            \n            if hit_rate < 70:\n                report_lines.append(\"  • معدل الإصابة منخفض - فكر في زيادة مدة التخزين المؤقت\")\n            \n            if avg_duration > 100:\n                report_lines.append(\"  • أوقات الاستجابة بطيئة - راجع الاستعلامات المعقدة\")\n            \n            if stats['summary']['avg_size_bytes'] > 50 * 1024:  # 50KB\n                report_lines.append(\"  • حجم الكائنات كبير - فكر في ضغط البيانات\")\n        \n        report_lines.extend([\n            \"\",\n            \"=\" * 60\n        ])\n        \n        return \"\\n\".join(report_lines)\n    \n    def _start_monitoring(self):\n        \"\"\"بدء المراقبة الدورية\"\"\"\n        \n        def monitor_loop():\n            while True:\n                try:\n                    # تنظيف المقاييس القديمة\n                    self._cleanup_old_metrics()\n                    \n                    # فحص حالة النظام\n                    self._check_system_health()\n                    \n                    # انتظار 5 دقائق\n                    time.sleep(300)\n                    \n                except Exception as e:\n                    logger.error(f'خطأ في حلقة المراقبة: {e}')\n                    time.sleep(60)  # انتظار دقيقة واحدة عند الخطأ\n        \n        # بدء الخيط في الخلفية\n        monitor_thread = threading.Thread(target=monitor_loop, daemon=True)\n        monitor_thread.start()\n    \n    def _cleanup_old_metrics(self):\n        \"\"\"تنظيف المقاييس القديمة\"\"\"\n        \n        cutoff_time = timezone.now() - timedelta(hours=24)\n        \n        with self.lock:\n            # إزالة المقاييس القديمة\n            old_count = len(self.metrics)\n            self.metrics = deque(\n                (m for m in self.metrics if m.timestamp >= cutoff_time),\n                maxlen=self.max_metrics\n            )\n            new_count = len(self.metrics)\n            \n            if old_count != new_count:\n                logger.info(f'تم تنظيف {old_count - new_count} مقياس قديم')\n            \n            # تنظيف التنبيهات القديمة\n            old_alerts_count = len(self.alerts)\n            self.alerts = [\n                a for a in self.alerts \n                if (timezone.now() - a['timestamp']).total_seconds() < 86400  # 24 ساعة\n            ]\n            \n            if old_alerts_count != len(self.alerts):\n                logger.info(f'تم تنظيف {old_alerts_count - len(self.alerts)} تنبيه قديم')\n    \n    def _check_system_health(self):\n        \"\"\"فحص حالة النظام العامة\"\"\"\n        \n        try:\n            # فحص آخر ساعة\n            recent_stats = self.get_stats(timedelta(hours=1))\n            \n            if 'summary' not in recent_stats:\n                return\n            \n            summary = recent_stats['summary']\n            \n            # تنبيه معدل الإصابة المنخفض\n            if summary['hit_rate'] < self.performance_thresholds['high_miss_rate']:\n                self.alerts.append({\n                    'type': 'low_hit_rate',\n                    'message': f'معدل إصابة منخفض: {summary[\"hit_rate\"]:.1f}%',\n                    'severity': 'warning',\n                    'timestamp': timezone.now(),\n                    'details': summary\n                })\n            \n            # تنبيه عدد العمليات المرتفع\n            if summary['total_operations'] > 10000:  # أكثر من 10k عملية في الساعة\n                self.alerts.append({\n                    'type': 'high_load',\n                    'message': f'حمولة عالية: {summary[\"total_operations\"]:,} عملية في الساعة',\n                    'severity': 'info',\n                    'timestamp': timezone.now(),\n                    'details': summary\n                })\n            \n        except Exception as e:\n            logger.error(f'خطأ في فحص حالة النظام: {e}')\n\n\n# مثيل عام للمراقب\ncache_monitor = CacheMonitor()\n\n\nclass MonitoredCacheService:\n    \"\"\"خدمة التخزين المؤقت مع المراقبة\"\"\"\n    \n    def __init__(self, cache_service):\n        self.cache_service = cache_service\n        self.monitor = cache_monitor\n    \n    def set(self, key: str, value: Any, timeout: int = 300, level: str = 'L1', tags: List[str] = None) -> bool:\n        \"\"\"حفظ مع المراقبة\"\"\"\n        \n        start_time = time.time()\n        \n        try:\n            # تقدير حجم البيانات\n            size = len(str(value).encode('utf-8'))\n            \n            # تنفيذ العملية\n            result = self.cache_service.set(key, value, timeout, level, tags)\n            \n            # تسجيل المقياس\n            duration = (time.time() - start_time) * 1000  # بالميلي ثانية\n            metric = CacheMetric(\n                timestamp=timezone.now(),\n                key=key,\n                operation='set',\n                size=size,\n                duration=duration,\n                level=level,\n                tags=tags or []\n            )\n            self.monitor.record_metric(metric)\n            \n            return result\n            \n        except Exception as e:\n            logger.error(f'خطأ في set مع المراقبة: {e}')\n            return False\n    \n    def get(self, key: str, level: str = 'L1', default: Any = None) -> Any:\n        \"\"\"استرجاع مع المراقبة\"\"\"\n        \n        start_time = time.time()\n        \n        try:\n            # تنفيذ العملية\n            result = self.cache_service.get(key, level, default)\n            \n            # تحديد نوع العملية\n            operation = 'hit' if result is not default else 'miss'\n            \n            # تسجيل المقياس\n            duration = (time.time() - start_time) * 1000\n            size = len(str(result).encode('utf-8')) if result is not default else 0\n            \n            metric = CacheMetric(\n                timestamp=timezone.now(),\n                key=key,\n                operation=operation,\n                size=size,\n                duration=duration,\n                level=level\n            )\n            self.monitor.record_metric(metric)\n            \n            return result\n            \n        except Exception as e:\n            logger.error(f'خطأ في get مع المراقبة: {e}')\n            return default\n    \n    def delete(self, key: str, level: str = 'L1') -> bool:\n        \"\"\"حذف مع المراقبة\"\"\"\n        \n        start_time = time.time()\n        \n        try:\n            # تنفيذ العملية\n            result = self.cache_service.delete(key, level)\n            \n            # تسجيل المقياس\n            duration = (time.time() - start_time) * 1000\n            metric = CacheMetric(\n                timestamp=timezone.now(),\n                key=key,\n                operation='delete',\n                duration=duration,\n                level=level\n            )\n            self.monitor.record_metric(metric)\n            \n            return result\n            \n        except Exception as e:\n            logger.error(f'خطأ في delete مع المراقبة: {e}')\n            return False"